function solve(nums: number[], k: number): number {
    let total = 0;
    let mod = 0;
    let map = new Map<number, number>();
    map.set(0, 1); // Base case: prefix sum 0 occurs once at index -1

    for (let i = 0; i < nums.length; i++) {
        total += nums[i];
        mod = (mod + total) % k;

        // If mod has been seen before, we can remove the subarray between the previous index and current index
        if (map.has(mod)) {
            // Calculate the number of elements removed
            let count = i - map.get(mod)!;
            // If count is even, we can remove the subarray and it doesn't affect the total sum
            if (count % 2 === 0) {
                return total - (count * nums[i] / 2);
            }
        }

        map.set(mod, i);
    }

    return total;
}

